INSERT INTO `sys_oper_log` VALUES (515, '发布文章', 1, 'com.ruoyi.web.controller.gamebox.GbArticleController.publishToStorage()', 'POST', 1, 'admin', '研发部门', '/gamebox/article/publish', '127.0.0.1', '内网IP', '{\"author\":\"Misin\",\"categoryIcon\":\"📖\",\"categoryId\":27,\"categoryName\":\"攻略\",\"commentCount\":0,\"content\":\"# 文章发布到存储功能说明\\n\\n## 功能概述\\n\\n文章管理页面已经升级，支持将 Markdown 格式的文章直接发布到对象存储（GitHub、MinIO、R2等），并自动生成访问URL。\\n\\n## 主要特性\\n\\n### 1. Markdown 编辑器\\n- 使用 `md-editor-v3` 实现所见即所得的 Markdown 编辑\\n- 支持实时预览\\n- 支持图片上传（当前支持 base64，可扩展到存储服务）\\n- 完整的 Markdown 语法支持（标题、列表、代码块、表格、公式等）\\n\\n### 2. 存储配置选择\\n- 支持选择已配置的存储服务（GitHub、MinIO、R2、OSS、COS等）\\n- 自动获取启用状态的存储配置列表\\n- 支持多种存储类型\\n\\n### 3. 路径规则配置\\n提供4种路径规则：\\n\\n| 规则 | 说明 | 示例 |\\n|------|------|------|\\n| 日期+标题 | `YYYY-MM-DD-{slug}` | `2025-12-23-game-guide/README.md` |\\n| 年月+标题 | `YYYY-MM-{slug}` | `2025-12-game-guide/README.md` |\\n| 时间戳+标题 | `{timestamp}-{slug}` | `1703312345678-game-guide/README.md` |\\n| 仅标题 | `{slug}` | `game-guide/README.md` |\\n\\n所有路径规则都会在末尾追加 `/README.md`\\n\\n### 4. 自动URL构建\\n发布后自动构建访问URL，优先级：\\n1. 自定义域名（`custom_domain`）\\n2. CDN URL（`cdn_url`）\\n3. 默认存储URL：\\n   - GitHub: `https://raw.githubusercontent.com/{owner}/{repo}/{branch}/{path}`\\n   - R2: 使用配置的 `r2_public_url`\\n\\n## 使用流程\\n\\n### 步骤1: 新建文章\\n1. 点击\\\"新增\\\"按钮\\n2. 填写基本信息：\\n   - **文章标题**（必填）\\n   - **Slug**（必填）：URL友好的标识符，如 `game-review-2025`\\n   - **分类**：选择文章分类\\n   - **作者**：文章作者\\n   - **语言**：选择语言（zh-CN、en-US、ja-JP）\\n\\n### 步骤2: 选择存储配置\\n1. 在\\\"存储配置\\\"下拉框中选择目标存储\\n2. 选择\\\"路径规则\\\"\\n3. 查看\\\"预览路径\\\"确认生成的文件路径\\n\\n### 步骤3: 编写内容\\n1. 在 Markdown 编辑器中编写文章内容\\n2. 支持直接粘贴 Markdown 格式文本\\n3. 使用工具栏插入各种元素（图片、表格、代码块等）\\n4. 实时预览效果\\n\\n### 步骤4: 补充信息\\n- **关键词**：多个关键词用逗号分隔\\n- **文章摘要**：简短描述\\n- **封面图**：封面图片URL\\n- **置顶**：是否置顶显示\\n- **推荐**：是否推荐\\n- **排序**：显示顺序\\n\\n### 步骤5: 发布\\n1. 点击\\\"发布到存储\\\"按钮\\n2. 系统将自动：\\n   - 验证必填字段\\n   - 将 Markdown 内容上传到选定的存储\\n   - 生成访问URL\\n   - 保存文章记录到数据库\\n   - 设置发布状态为\\\"已发布\\\"\\n\\n## 数据库字段说明\\n\\n### 文章表 (gb_articles) 关键字段\\n\\n| 字段名 | 类型 | 说明 |\\n|--------|------|------|\\n| `slug` | varchar(255) | 文章路径标识，用于生成URL |\\n| `locale` | varchar(10) | 文章语言代码 |\\n| `storage_config_id` | bigint | 使用的存储配置ID |\\n| `storage_key` | varchar(500) | 文件在存储中的完整路径 |\\n| `storage_url` | varchar(1000) | 文章的完整访问URL |\\n| `is_published` | char(1)', '{\"msg\":\"发布成功\",\"code\":200,\"data\":{\"author\":\"Misin\",\"categoryIcon\":\"📖\",\"categoryId\":27,\"categoryName\":\"攻略\",\"commentCount\":0,\"content\":\"# 文章发布到存储功能说明\\n\\n## 功能概述\\n\\n文章管理页面已经升级，支持将 Markdown 格式的文章直接发布到对象存储（GitHub、MinIO、R2等），并自动生成访问URL。\\n\\n## 主要特性\\n\\n### 1. Markdown 编辑器\\n- 使用 `md-editor-v3` 实现所见即所得的 Markdown 编辑\\n- 支持实时预览\\n- 支持图片上传（当前支持 base64，可扩展到存储服务）\\n- 完整的 Markdown 语法支持（标题、列表、代码块、表格、公式等）\\n\\n### 2. 存储配置选择\\n- 支持选择已配置的存储服务（GitHub、MinIO、R2、OSS、COS等）\\n- 自动获取启用状态的存储配置列表\\n- 支持多种存储类型\\n\\n### 3. 路径规则配置\\n提供4种路径规则：\\n\\n| 规则 | 说明 | 示例 |\\n|------|------|------|\\n| 日期+标题 | `YYYY-MM-DD-{slug}` | `2025-12-23-game-guide/README.md` |\\n| 年月+标题 | `YYYY-MM-{slug}` | `2025-12-game-guide/README.md` |\\n| 时间戳+标题 | `{timestamp}-{slug}` | `1703312345678-game-guide/README.md` |\\n| 仅标题 | `{slug}` | `game-guide/README.md` |\\n\\n所有路径规则都会在末尾追加 `/README.md`\\n\\n### 4. 自动URL构建\\n发布后自动构建访问URL，优先级：\\n1. 自定义域名（`custom_domain`）\\n2. CDN URL（`cdn_url`）\\n3. 默认存储URL：\\n   - GitHub: `https://raw.githubusercontent.com/{owner}/{repo}/{branch}/{path}`\\n   - R2: 使用配置的 `r2_public_url`\\n\\n## 使用流程\\n\\n### 步骤1: 新建文章\\n1. 点击\\\"新增\\\"按钮\\n2. 填写基本信息：\\n   - **文章标题**（必填）\\n   - **Slug**（必填）：URL友好的标识符，如 `game-review-2025`\\n   - **分类**：选择文章分类\\n   - **作者**：文章作者\\n   - **语言**：选择语言（zh-CN、en-US、ja-JP）\\n\\n### 步骤2: 选择存储配置\\n1. 在\\\"存储配置\\\"下拉框中选择目标存储\\n2. 选择\\\"路径规则\\\"\\n3. 查看\\\"预览路径\\\"确认生成的文件路径\\n\\n### 步骤3: 编写内容\\n1. 在 Markdown 编辑器中编写文章内容\\n2. 支持直接粘贴 Markdown 格式文本\\n3. 使用工具栏插入各种元素（图片、表格、代码块等）\\n4. 实时预览效果\\n\\n### 步骤4: 补充信息\\n- **关键词**：多个关键词用逗号分隔\\n- **文章摘要**：简短描述\\n- **封面图**：封面图片URL\\n- **置顶**：是否置顶显示\\n- **推荐**：是否推荐\\n- **排序**：显示顺序\\n\\n### 步骤5: 发布\\n1. 点击\\\"发布到存储\\\"按钮\\n2. 系统将自动：\\n   - 验证必填字段\\n   - 将 Markdown 内容上传到选定的存储\\n   - 生成访问URL\\n   - 保存文章记录到数据库\\n   - 设置发布状态为\\\"已发布\\\"\\n\\n## 数据库字段说明\\n\\n### 文章表 (gb_articles) 关键字段\\n\\n| 字段名 | 类型 | 说明 |\\n|--------|------|------|\\n| `slug` | varchar(255) | 文章路径标识，用于生成URL |\\n| `locale` | varchar(10) | 文章语言代码 |\\n| `storage_config_id` | bigint | 使用的存储配置ID |\\n| `storage_key` | varchar(500) | 文件在存储中的完整路径 |\\n| `storage_url` | varchar(1000) | 文章的完整访问U', 0, NULL, '2025-12-23 11:46:55', 77);
INSERT INTO `sys_oper_log` VALUES (516, '发布文章', 1, 'com.ruoyi.web.controller.gamebox.GbArticleController.publishToStorage()', 'POST', 1, 'admin', '研发部门', '/gamebox/article/publish', '127.0.0.1', '内网IP', '{\"author\":\"Misin\",\"categoryIcon\":\"📖\",\"categoryId\":27,\"categoryName\":\"攻略\",\"commentCount\":0,\"content\":\"# 文章发布到存储功能说明\\n\\n## 功能概述\\n\\n文章管理页面已经升级，支持将 Markdown 格式的文章直接发布到对象存储（GitHub、MinIO、R2等），并自动生成访问URL。\\n\\n## 主要特性\\n\\n### 1. Markdown 编辑器\\n- 使用 `md-editor-v3` 实现所见即所得的 Markdown 编辑\\n- 支持实时预览\\n- 支持图片上传（当前支持 base64，可扩展到存储服务）\\n- 完整的 Markdown 语法支持（标题、列表、代码块、表格、公式等）\\n\\n### 2. 存储配置选择\\n- 支持选择已配置的存储服务（GitHub、MinIO、R2、OSS、COS等）\\n- 自动获取启用状态的存储配置列表\\n- 支持多种存储类型\\n\\n### 3. 路径规则配置\\n提供4种路径规则：\\n\\n| 规则 | 说明 | 示例 |\\n|------|------|------|\\n| 日期+标题 | `YYYY-MM-DD-{slug}` | `2025-12-23-game-guide/README.md` |\\n| 年月+标题 | `YYYY-MM-{slug}` | `2025-12-game-guide/README.md` |\\n| 时间戳+标题 | `{timestamp}-{slug}` | `1703312345678-game-guide/README.md` |\\n| 仅标题 | `{slug}` | `game-guide/README.md` |\\n\\n所有路径规则都会在末尾追加 `/README.md`\\n\\n### 4. 自动URL构建\\n发布后自动构建访问URL，优先级：\\n1. 自定义域名（`custom_domain`）\\n2. CDN URL（`cdn_url`）\\n3. 默认存储URL：\\n   - GitHub: `https://raw.githubusercontent.com/{owner}/{repo}/{branch}/{path}`\\n   - R2: 使用配置的 `r2_public_url`\\n\\n## 使用流程\\n\\n### 步骤1: 新建文章\\n1. 点击\\\"新增\\\"按钮\\n2. 填写基本信息：\\n   - **文章标题**（必填）\\n   - **Slug**（必填）：URL友好的标识符，如 `game-review-2025`\\n   - **分类**：选择文章分类\\n   - **作者**：文章作者\\n   - **语言**：选择语言（zh-CN、en-US、ja-JP）\\n\\n### 步骤2: 选择存储配置\\n1. 在\\\"存储配置\\\"下拉框中选择目标存储\\n2. 选择\\\"路径规则\\\"\\n3. 查看\\\"预览路径\\\"确认生成的文件路径\\n\\n### 步骤3: 编写内容\\n1. 在 Markdown 编辑器中编写文章内容\\n2. 支持直接粘贴 Markdown 格式文本\\n3. 使用工具栏插入各种元素（图片、表格、代码块等）\\n4. 实时预览效果\\n\\n### 步骤4: 补充信息\\n- **关键词**：多个关键词用逗号分隔\\n- **文章摘要**：简短描述\\n- **封面图**：封面图片URL\\n- **置顶**：是否置顶显示\\n- **推荐**：是否推荐\\n- **排序**：显示顺序\\n\\n### 步骤5: 发布\\n1. 点击\\\"发布到存储\\\"按钮\\n2. 系统将自动：\\n   - 验证必填字段\\n   - 将 Markdown 内容上传到选定的存储\\n   - 生成访问URL\\n   - 保存文章记录到数据库\\n   - 设置发布状态为\\\"已发布\\\"\\n\\n## 数据库字段说明\\n\\n### 文章表 (gb_articles) 关键字段\\n\\n| 字段名 | 类型 | 说明 |\\n|--------|------|------|\\n| `slug` | varchar(255) | 文章路径标识，用于生成URL |\\n| `locale` | varchar(10) | 文章语言代码 |\\n| `storage_config_id` | bigint | 使用的存储配置ID |\\n| `storage_key` | varchar(500) | 文件在存储中的完整路径 |\\n| `storage_url` | varchar(1000) | 文章的完整访问URL |\\n| `is_published` | char(1)', '{\"msg\":\"发布失败: 更新GitHub文件失败: https://api.github.com/repos/MisinGuo/temp/contents/2025-12-23-nihao/README.md?ref=main {\\\"message\\\":\\\"Not Found\\\",\\\"documentation_url\\\":\\\"https://docs.github.com/rest/repos/contents#get-repository-content\\\",\\\"status\\\":\\\"404\\\"}\",\"code\":500}', 0, NULL, '2025-12-23 12:06:10', 2018);
INSERT INTO `sys_oper_log` VALUES (517, '发布文章', 1, 'com.ruoyi.web.controller.gamebox.GbArticleController.publishToStorage()', 'POST', 1, 'admin', '研发部门', '/gamebox/article/publish', '127.0.0.1', '内网IP', '{\"author\":\"Misin\",\"categoryIcon\":\"📖\",\"categoryId\":27,\"categoryName\":\"攻略\",\"commentCount\":0,\"content\":\"# 文章发布到存储功能说明\\n\\n## 功能概述\\n\\n文章管理页面已经升级，支持将 Markdown 格式的文章直接发布到对象存储（GitHub、MinIO、R2等），并自动生成访问URL。\\n\\n## 主要特性\\n\\n### 1. Markdown 编辑器\\n- 使用 `md-editor-v3` 实现所见即所得的 Markdown 编辑\\n- 支持实时预览\\n- 支持图片上传（当前支持 base64，可扩展到存储服务）\\n- 完整的 Markdown 语法支持（标题、列表、代码块、表格、公式等）\\n\\n### 2. 存储配置选择\\n- 支持选择已配置的存储服务（GitHub、MinIO、R2、OSS、COS等）\\n- 自动获取启用状态的存储配置列表\\n- 支持多种存储类型\\n\\n### 3. 路径规则配置\\n提供4种路径规则：\\n\\n| 规则 | 说明 | 示例 |\\n|------|------|------|\\n| 日期+标题 | `YYYY-MM-DD-{slug}` | `2025-12-23-game-guide/README.md` |\\n| 年月+标题 | `YYYY-MM-{slug}` | `2025-12-game-guide/README.md` |\\n| 时间戳+标题 | `{timestamp}-{slug}` | `1703312345678-game-guide/README.md` |\\n| 仅标题 | `{slug}` | `game-guide/README.md` |\\n\\n所有路径规则都会在末尾追加 `/README.md`\\n\\n### 4. 自动URL构建\\n发布后自动构建访问URL，优先级：\\n1. 自定义域名（`custom_domain`）\\n2. CDN URL（`cdn_url`）\\n3. 默认存储URL：\\n   - GitHub: `https://raw.githubusercontent.com/{owner}/{repo}/{branch}/{path}`\\n   - R2: 使用配置的 `r2_public_url`\\n\\n## 使用流程\\n\\n### 步骤1: 新建文章\\n1. 点击\\\"新增\\\"按钮\\n2. 填写基本信息：\\n   - **文章标题**（必填）\\n   - **Slug**（必填）：URL友好的标识符，如 `game-review-2025`\\n   - **分类**：选择文章分类\\n   - **作者**：文章作者\\n   - **语言**：选择语言（zh-CN、en-US、ja-JP）\\n\\n### 步骤2: 选择存储配置\\n1. 在\\\"存储配置\\\"下拉框中选择目标存储\\n2. 选择\\\"路径规则\\\"\\n3. 查看\\\"预览路径\\\"确认生成的文件路径\\n\\n### 步骤3: 编写内容\\n1. 在 Markdown 编辑器中编写文章内容\\n2. 支持直接粘贴 Markdown 格式文本\\n3. 使用工具栏插入各种元素（图片、表格、代码块等）\\n4. 实时预览效果\\n\\n### 步骤4: 补充信息\\n- **关键词**：多个关键词用逗号分隔\\n- **文章摘要**：简短描述\\n- **封面图**：封面图片URL\\n- **置顶**：是否置顶显示\\n- **推荐**：是否推荐\\n- **排序**：显示顺序\\n\\n### 步骤5: 发布\\n1. 点击\\\"发布到存储\\\"按钮\\n2. 系统将自动：\\n   - 验证必填字段\\n   - 将 Markdown 内容上传到选定的存储\\n   - 生成访问URL\\n   - 保存文章记录到数据库\\n   - 设置发布状态为\\\"已发布\\\"\\n\\n## 数据库字段说明\\n\\n### 文章表 (gb_articles) 关键字段\\n\\n| 字段名 | 类型 | 说明 |\\n|--------|------|------|\\n| `slug` | varchar(255) | 文章路径标识，用于生成URL |\\n| `locale` | varchar(10) | 文章语言代码 |\\n| `storage_config_id` | bigint | 使用的存储配置ID |\\n| `storage_key` | varchar(500) | 文件在存储中的完整路径 |\\n| `storage_url` | varchar(1000) | 文章的完整访问URL |\\n| `is_published` | char(1)', '{\"msg\":\"发布成功\",\"code\":200,\"data\":{\"author\":\"Misin\",\"categoryIcon\":\"📖\",\"categoryId\":27,\"categoryName\":\"攻略\",\"commentCount\":0,\"content\":\"# 文章发布到存储功能说明\\n\\n## 功能概述\\n\\n文章管理页面已经升级，支持将 Markdown 格式的文章直接发布到对象存储（GitHub、MinIO、R2等），并自动生成访问URL。\\n\\n## 主要特性\\n\\n### 1. Markdown 编辑器\\n- 使用 `md-editor-v3` 实现所见即所得的 Markdown 编辑\\n- 支持实时预览\\n- 支持图片上传（当前支持 base64，可扩展到存储服务）\\n- 完整的 Markdown 语法支持（标题、列表、代码块、表格、公式等）\\n\\n### 2. 存储配置选择\\n- 支持选择已配置的存储服务（GitHub、MinIO、R2、OSS、COS等）\\n- 自动获取启用状态的存储配置列表\\n- 支持多种存储类型\\n\\n### 3. 路径规则配置\\n提供4种路径规则：\\n\\n| 规则 | 说明 | 示例 |\\n|------|------|------|\\n| 日期+标题 | `YYYY-MM-DD-{slug}` | `2025-12-23-game-guide/README.md` |\\n| 年月+标题 | `YYYY-MM-{slug}` | `2025-12-game-guide/README.md` |\\n| 时间戳+标题 | `{timestamp}-{slug}` | `1703312345678-game-guide/README.md` |\\n| 仅标题 | `{slug}` | `game-guide/README.md` |\\n\\n所有路径规则都会在末尾追加 `/README.md`\\n\\n### 4. 自动URL构建\\n发布后自动构建访问URL，优先级：\\n1. 自定义域名（`custom_domain`）\\n2. CDN URL（`cdn_url`）\\n3. 默认存储URL：\\n   - GitHub: `https://raw.githubusercontent.com/{owner}/{repo}/{branch}/{path}`\\n   - R2: 使用配置的 `r2_public_url`\\n\\n## 使用流程\\n\\n### 步骤1: 新建文章\\n1. 点击\\\"新增\\\"按钮\\n2. 填写基本信息：\\n   - **文章标题**（必填）\\n   - **Slug**（必填）：URL友好的标识符，如 `game-review-2025`\\n   - **分类**：选择文章分类\\n   - **作者**：文章作者\\n   - **语言**：选择语言（zh-CN、en-US、ja-JP）\\n\\n### 步骤2: 选择存储配置\\n1. 在\\\"存储配置\\\"下拉框中选择目标存储\\n2. 选择\\\"路径规则\\\"\\n3. 查看\\\"预览路径\\\"确认生成的文件路径\\n\\n### 步骤3: 编写内容\\n1. 在 Markdown 编辑器中编写文章内容\\n2. 支持直接粘贴 Markdown 格式文本\\n3. 使用工具栏插入各种元素（图片、表格、代码块等）\\n4. 实时预览效果\\n\\n### 步骤4: 补充信息\\n- **关键词**：多个关键词用逗号分隔\\n- **文章摘要**：简短描述\\n- **封面图**：封面图片URL\\n- **置顶**：是否置顶显示\\n- **推荐**：是否推荐\\n- **排序**：显示顺序\\n\\n### 步骤5: 发布\\n1. 点击\\\"发布到存储\\\"按钮\\n2. 系统将自动：\\n   - 验证必填字段\\n   - 将 Markdown 内容上传到选定的存储\\n   - 生成访问URL\\n   - 保存文章记录到数据库\\n   - 设置发布状态为\\\"已发布\\\"\\n\\n## 数据库字段说明\\n\\n### 文章表 (gb_articles) 关键字段\\n\\n| 字段名 | 类型 | 说明 |\\n|--------|------|------|\\n| `slug` | varchar(255) | 文章路径标识，用于生成URL |\\n| `locale` | varchar(10) | 文章语言代码 |\\n| `storage_config_id` | bigint | 使用的存储配置ID |\\n| `storage_key` | varchar(500) | 文件在存储中的完整路径 |\\n| `storage_url` | varchar(1000) | 文章的完整访问U', 0, NULL, '2025-12-23 12:06:44', 68);
